import{_ as a,c as s,o as l,a1 as t}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Vercel 一键部署：零认证快速发布应用 | Agent Skills 教程","description":"学习使用 Agent Skills 的 Vercel Deploy 功能，一键部署项目到 Vercel。本教程介绍自动框架检测、零认证部署、预览链接获取等特性，支持 40+ 种前端框架和静态网站，帮助你快速分享 demo 或在线预览应用。","frontmatter":{"title":"Vercel 一键部署：零认证快速发布应用 | Agent Skills 教程","sidebarTitle":"一句话部署到 Vercel","subtitle":"Vercel 一键部署：零认证快速发布应用","description":"学习使用 Agent Skills 的 Vercel Deploy 功能，一键部署项目到 Vercel。本教程介绍自动框架检测、零认证部署、预览链接获取等特性，支持 40+ 种前端框架和静态网站，帮助你快速分享 demo 或在线预览应用。","tags":["Vercel","部署","一键部署","前端框架"],"order":50,"prerequisite":["start-installation"]},"headers":[],"relativePath":"zh/vercel-labs/agent-skills/platforms/vercel-deploy/index.md","filePath":"zh/vercel-labs/agent-skills/platforms/vercel-deploy/index.md"}'),i={name:"zh/vercel-labs/agent-skills/platforms/vercel-deploy/index.md"};function n(o,e,p,r,d,c){return l(),s("div",null,[...e[0]||(e[0]=[t(`<h1 id="vercel-一键部署-零认证快速发布应用" tabindex="-1">Vercel 一键部署：零认证快速发布应用 <a class="header-anchor" href="#vercel-一键部署-零认证快速发布应用" aria-label="Permalink to &quot;Vercel 一键部署：零认证快速发布应用&quot;">​</a></h1><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to &quot;学完你能做什么&quot;">​</a></h2><ul><li>一句话让 Claude 把你的项目部署到 Vercel，无需手动配置</li><li>获取可访问的预览链接和所有权转移链接</li><li>自动识别项目框架（Next.js、React、Vue、Svelte 等 40+ 种）</li><li>处理静态 HTML 网站，支持单文件重命名</li></ul><h2 id="你现在的困境" tabindex="-1">你现在的困境 <a class="header-anchor" href="#你现在的困境" aria-label="Permalink to &quot;你现在的困境&quot;">​</a></h2><p>每次想把项目分享给别人，都需要：</p><ol><li>手动登录 Vercel 网站</li><li>创建新项目</li><li>连接 Git 仓库</li><li>等待构建完成</li><li>记住一长串 URL 分享给他人</li></ol><p>如果只是想快速展示一个 demo 或原型，这些步骤太繁琐了。</p><h2 id="什么时候用这一招" tabindex="-1">什么时候用这一招 <a class="header-anchor" href="#什么时候用这一招" aria-label="Permalink to &quot;什么时候用这一招&quot;">​</a></h2><p>适合以下场景：</p><ul><li>🚀 快速创建项目预览分享给团队</li><li>📦 展示 demo 给客户或朋友</li><li>🔄 CI/CD 中自动生成预览部署</li><li>🌐 部署静态 HTML 页面或单页应用</li></ul><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p>Vercel Deploy 技能的工作流程很简单：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你的说话 → Claude 检测到关键词 → 激活部署技能</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>          检测框架类型（从 package.json）</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>          打包项目（排除 node_modules 和 .git）</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>          上传到 Vercel API</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>          返回两个链接（预览 + 所有权转移）</span></span></code></pre></div><p><strong>为什么需要两个链接？</strong></p><ul><li><strong>Preview URL</strong>: 立即可访问的预览地址</li><li><strong>Claim URL</strong>: 把这个部署转到你的 Vercel 账户下管理</li></ul><p>这样设计的好处：部署者（Agent）不需要你的账户权限，你可以在之后通过 Claim URL 获得所有权。</p><h2 id="🎒-开始前的准备" tabindex="-1">🎒 开始前的准备 <a class="header-anchor" href="#🎒-开始前的准备" aria-label="Permalink to &quot;🎒 开始前的准备&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">前置检查</p><ul><li>✅ 已完成 <a href="./../installation/">Agent Skills 安装</a></li><li>✅ 项目目录结构完整（有 <code>package.json</code> 或是静态 HTML 项目）</li><li>✅ Claude.ai 网络权限已配置（如使用 claude.ai）</li></ul></div><div class="info custom-block"><p class="custom-block-title">网络权限提醒</p><p>如果你使用 <strong>claude.ai</strong>（在线版），需要允许访问 <code>*.vercel.com</code> 域名：</p><ol><li>前往 <a href="https://claude.ai/settings/capabilities" target="_blank" rel="noreferrer">https://claude.ai/settings/capabilities</a></li><li>在白名单中添加 <code>*.vercel.com</code></li><li>保存设置后重试</li></ol><p>如果你的部署失败并提示网络错误，请检查这个设置。</p></div><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-切换到项目目录" tabindex="-1">第 1 步：切换到项目目录 <a class="header-anchor" href="#第-1-步-切换到项目目录" aria-label="Permalink to &quot;第 1 步：切换到项目目录&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 进入你的项目目录</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /path/to/your/project</span></span></code></pre></div><p><strong>为什么</strong> 部署脚本需要找到项目的 <code>package.json</code> 和源文件，目录定位很重要。</p><h3 id="第-2-步-告诉-claude-部署" tabindex="-1">第 2 步：告诉 Claude 部署 <a class="header-anchor" href="#第-2-步-告诉-claude-部署" aria-label="Permalink to &quot;第 2 步：告诉 Claude 部署&quot;">​</a></h3><p>在 Claude 对话中输入：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Deploy my app to Vercel</span></span></code></pre></div><p>你还可以试试这些触发词：</p><ul><li>&quot;Deploy this to production&quot;</li><li>&quot;Deploy and give me the link&quot;</li><li>&quot;Push this live&quot;</li><li>&quot;Create a preview deployment&quot;</li></ul><h3 id="第-3-步-观察部署过程" tabindex="-1">第 3 步：观察部署过程 <a class="header-anchor" href="#第-3-步-观察部署过程" aria-label="Permalink to &quot;第 3 步：观察部署过程&quot;">​</a></h3><p>你会看到类似输出：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Preparing deployment...</span></span>
<span class="line"><span>Detected framework: nextjs</span></span>
<span class="line"><span>Creating deployment package...</span></span>
<span class="line"><span>Deploying...</span></span>
<span class="line"><span>✓ Deployment successful!</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Preview URL: https://skill-deploy-abc123.vercel.app</span></span>
<span class="line"><span>Claim URL:   https://vercel.com/claim-deployment?code=...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>View your site at the Preview URL.</span></span>
<span class="line"><span>To transfer this deployment to your Vercel account, visit the Claim URL.</span></span></code></pre></div><p>同时，Claude 还会输出 JSON 格式（方便脚本解析）：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;previewUrl&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://skill-deploy-abc123.vercel.app&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;claimUrl&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://vercel.com/claim-deployment?code=...&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;deploymentId&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;dpl_...&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;projectId&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;prj_...&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>你应该看到</strong>：</p><ul><li>部署成功提示 ✓</li><li>两个 URL（preview 和 claim）</li><li>如果是代码项目，还会显示检测到的框架名称</li></ul><h3 id="第-4-步-访问预览链接" tabindex="-1">第 4 步：访问预览链接 <a class="header-anchor" href="#第-4-步-访问预览链接" aria-label="Permalink to &quot;第 4 步：访问预览链接&quot;">​</a></h3><p><strong>点击 Preview URL</strong>，你就能看到网站实时上线了！</p><p>如果这是一个 demo 或临时展示，任务就完成了。</p><h3 id="第-5-步-可选-转移所有权" tabindex="-1">第 5 步：（可选）转移所有权 <a class="header-anchor" href="#第-5-步-可选-转移所有权" aria-label="Permalink to &quot;第 5 步：（可选）转移所有权&quot;">​</a></h3><p>如果你想长期管理这个部署：</p><ol><li>点击 <strong>Claim URL</strong></li><li>登录你的 Vercel 账户</li><li>确认转移</li><li>部署现在属于你的账户，可以继续编辑和管理</li></ol><p><strong>你应该看到</strong>：</p><ul><li>部署出现在你的 Vercel 账户下</li><li>可以在 Vercel Dashboard 中查看日志、重新部署等</li></ul><h2 id="检查点-✅" tabindex="-1">检查点 ✅ <a class="header-anchor" href="#检查点-✅" aria-label="Permalink to &quot;检查点 ✅&quot;">​</a></h2><p>部署完成后，确认以下内容：</p><ul><li>[ ] Preview URL 可以在浏览器中访问</li><li>[ ] 页面显示正常（没有 404 或构建错误）</li><li>[ ] 如果是代码项目，框架检测正确（Next.js、Vite 等）</li><li>[ ] 如需长期管理，已通过 Claim URL 转移所有权</li></ul><h2 id="支持的框架" tabindex="-1">支持的框架 <a class="header-anchor" href="#支持的框架" aria-label="Permalink to &quot;支持的框架&quot;">​</a></h2><p>Vercel Deploy 技能可以自动检测 <strong>40+ 种框架</strong>：</p><table tabindex="0"><thead><tr><th>类别</th><th>框架（部分示例）</th></tr></thead><tbody><tr><td><strong>React</strong></td><td>Next.js, Gatsby, Create React App, Remix</td></tr><tr><td><strong>Vue</strong></td><td>Nuxt, Vitepress, Vuepress</td></tr><tr><td><strong>Svelte</strong></td><td>SvelteKit, Svelte</td></tr><tr><td><strong>Angular</strong></td><td>Angular, Ionic Angular</td></tr><tr><td><strong>Node.js 后端</strong></td><td>Express, Hono, Fastify, NestJS</td></tr><tr><td><strong>构建工具</strong></td><td>Vite, Parcel</td></tr><tr><td><strong>其他</strong></td><td>Astro, Solid Start, Ember, Astro, Hexo, Eleventy</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">框架检测原理</p><p>脚本会读取你的 <code>package.json</code>，检查 <code>dependencies</code> 和 <code>devDependencies</code> 中的包名。</p><p>如果存在多个匹配，脚本会按优先级选择最具体的框架（例如 Next.js 优先于通用的 React）。</p></div><h2 id="静态-html-项目" tabindex="-1">静态 HTML 项目 <a class="header-anchor" href="#静态-html-项目" aria-label="Permalink to &quot;静态 HTML 项目&quot;">​</a></h2><p>如果你的项目<strong>没有</strong> <code>package.json</code>（纯静态网站），部署技能会智能处理：</p><ul><li><strong>自动检测</strong>：识别根目录下的 <code>.html</code> 文件</li><li><strong>重命名</strong>：如果只有一个 <code>.html</code> 文件且不是 <code>index.html</code>，会自动重命名为 <code>index.html</code></li><li><strong>直接部署</strong>：作为静态站点托管到 Vercel</li></ul><p><strong>示例场景</strong>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">my-static-site/</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">└──</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> demo.html</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 会自动重命名为 index.html</span></span></code></pre></div><p>部署后，访问预览链接就能看到 <code>demo.html</code> 的内容。</p><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><h3 id="问题-1-部署失败-提示网络错误" tabindex="-1">问题 1：部署失败，提示网络错误 <a class="header-anchor" href="#问题-1-部署失败-提示网络错误" aria-label="Permalink to &quot;问题 1：部署失败，提示网络错误&quot;">​</a></h3><p><strong>现象</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Error: Network Egress Error</span></span></code></pre></div><p><strong>原因</strong>：claude.ai 默认阻止访问外部域。</p><p><strong>解决方法</strong>：</p><ol><li>前往 <a href="https://claude.ai/settings/capabilities" target="_blank" rel="noreferrer">https://claude.ai/settings/capabilities</a></li><li>添加 <code>*.vercel.com</code> 到白名单</li><li>重新部署</li></ol><h3 id="问题-2-框架检测不准确" tabindex="-1">问题 2：框架检测不准确 <a class="header-anchor" href="#问题-2-框架检测不准确" aria-label="Permalink to &quot;问题 2：框架检测不准确&quot;">​</a></h3><p><strong>现象</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Detected framework: vite</span></span>
<span class="line"><span># 但你期待的是 nextjs</span></span></code></pre></div><p><strong>原因</strong>：脚本按依赖优先级匹配，可能在检测到 <code>vite</code> 后就停止了。</p><p><strong>解决方法</strong>：</p><ul><li>检查 <code>package.json</code> 中的依赖顺序</li><li>如果不影响部署，可以忽略（Vercel 会自动构建）</li><li>项目仍能正常部署，只是可能使用默认的 Vite 配置</li></ul><h3 id="问题-3-静态网站-404" tabindex="-1">问题 3：静态网站 404 <a class="header-anchor" href="#问题-3-静态网站-404" aria-label="Permalink to &quot;问题 3：静态网站 404&quot;">​</a></h3><p><strong>现象</strong>： 单个 <code>.html</code> 文件部署后访问 404。</p><p><strong>解决方法</strong>： 确保 HTML 文件在项目根目录。如果文件在子目录，Vercel 默认不会将其路由到根路径。</p><p><strong>正确结构</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>project/</span></span>
<span class="line"><span>└── my-site.html  # 根目录下的单个文件，会自动重命名为 index.html</span></span></code></pre></div><p><strong>错误结构</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>project/</span></span>
<span class="line"><span>└── dist/</span></span>
<span class="line"><span>    └── my-site.html  # 不会自动重命名，访问会 404</span></span></code></pre></div><h3 id="问题-4-部署成功但页面报错" tabindex="-1">问题 4：部署成功但页面报错 <a class="header-anchor" href="#问题-4-部署成功但页面报错" aria-label="Permalink to &quot;问题 4：部署成功但页面报错&quot;">​</a></h3><p><strong>现象</strong>： 部署成功，但访问页面时显示构建错误或运行时错误。</p><p><strong>解决方法</strong>：</p><ul><li>在本地运行 <code>npm run build</code> 检查是否通过</li><li>查看部署日志（如果已转移到自己的 Vercel 账户）</li><li>检查环境变量（如果项目依赖 <code>.env</code>）</li></ul><div class="tip custom-block"><p class="custom-block-title">自动排除文件</p><p>部署脚本会自动排除：</p><ul><li><code>node_modules/</code>（避免上传依赖）</li><li><code>.git/</code>（避免上传版本历史）</li></ul><p>如果你的项目需要排除其他文件（如 <code>.env</code>），建议在手动打包时处理。</p></div><h2 id="高级用法" tabindex="-1">高级用法 <a class="header-anchor" href="#高级用法" aria-label="Permalink to &quot;高级用法&quot;">​</a></h2><h3 id="指定部署路径" tabindex="-1">指定部署路径 <a class="header-anchor" href="#指定部署路径" aria-label="Permalink to &quot;指定部署路径&quot;">​</a></h3><p>你也可以指定其他目录的部署：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Deploy the project at ./my-app</span></span></code></pre></div><p>Claude 会使用该路径进行部署。</p><h3 id="从已有-tarball-部署" tabindex="-1">从已有 tarball 部署 <a class="header-anchor" href="#从已有-tarball-部署" aria-label="Permalink to &quot;从已有 tarball 部署&quot;">​</a></h3><p>如果你已经有打包好的 <code>.tgz</code> 文件：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Deploy /path/to/project.tgz to Vercel</span></span></code></pre></div><p>脚本会直接上传已有的压缩包，跳过打包步骤。</p><h2 id="本课小结" tabindex="-1">本课小结 <a class="header-anchor" href="#本课小结" aria-label="Permalink to &quot;本课小结&quot;">​</a></h2><p>Vercel Deploy 技能让部署变得前所未有的简单：</p><p><strong>核心价值</strong>：</p><ul><li>✅ 一句话完成部署，无需手动配置</li><li>✅ 自动检测框架，支持 40+ 种技术栈</li><li>✅ 零认证部署，安全性高</li><li>✅ 返回预览链接 + 所有权转移链接</li></ul><p><strong>适用场景</strong>：</p><ul><li>🚀 快速分享 demo 或原型</li><li>📦 团队内部预览</li><li>🔄 自动化 CI/CD 流程</li><li>🌐 静态网站托管</li></ul><p><strong>下一步</strong>： 如果你想深入探究技能的工作原理，可以查看 <a href="./../react-best-practices/">React 性能优化最佳实践</a> 或学习如何 <a href="./../../advanced/skill-development/">开发自定义技能</a>。</p><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><blockquote><p>下一课我们学习 <strong><a href="./../react-best-practices/">React/Next.js 性能优化最佳实践</a></strong>。</p><p>你会学到：</p><ul><li>57 条 React 性能优化规则</li><li>如何消除瀑布流、优化打包大小</li><li>Agent 如何自动检查代码并给出修复建议</li></ul></blockquote><hr><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to &quot;附录：源码参考&quot;">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-01-25</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>文件路径</th><th>行号</th></tr></thead><tbody><tr><td>部署脚本入口</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/skills/claude.ai/vercel-deploy-claimable/scripts/deploy.sh" target="_blank" rel="noreferrer"><code>skills/claude.ai/vercel-deploy-claimable/scripts/deploy.sh</code></a></td><td>1-250</td></tr><tr><td>框架检测逻辑</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/skills/claude.ai/vercel-deploy-claimable/scripts/deploy.sh" target="_blank" rel="noreferrer"><code>deploy.sh</code></a></td><td>12-156</td></tr><tr><td>打包并上传到 API</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/skills/claude.ai/vercel-deploy-claimable/scripts/deploy.sh" target="_blank" rel="noreferrer"><code>deploy.sh</code></a></td><td>208-222</td></tr><tr><td>静态 HTML 重命名</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/skills/claude.ai/vercel-deploy-claimable/scripts/deploy.sh" target="_blank" rel="noreferrer"><code>deploy.sh</code></a></td><td>192-205</td></tr><tr><td>技能定义文档</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/skills/claude.ai/vercel-deploy-claimable/SKILL.md" target="_blank" rel="noreferrer"><code>skills/claude.ai/vercel-deploy-claimable/SKILL.md</code></a></td><td>1-113</td></tr><tr><td>网络错误排查</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/skills/claude.ai/vercel-deploy-claimable/SKILL.md" target="_blank" rel="noreferrer"><code>SKILL.md</code></a></td><td>102-112</td></tr></tbody></table><p><strong>关键常量</strong>：</p><ul><li><code>DEPLOY_ENDPOINT = &quot;https://claude-skills-deploy.vercel.com/api/deploy&quot;</code>：Vercel 部署 API 端点</li></ul><p><strong>关键函数</strong>：</p><ul><li><code>detect_framework()</code>：从 package.json 检测 40+ 种框架</li></ul><p><strong>支持的框架检测</strong>（按优先级排序）：</p><ul><li>React 类：Next.js, Gatsby, Remix, React Router</li><li>Vue 类：Nuxt, Vitepress, Vuepress</li><li>Svelte 类：SvelteKit, Svelte</li><li>其他：Astro, Angular, Express, Hono, Vite, Parcel 等</li></ul></details>`,102)])])}const g=a(i,[["render",n]]);export{u as __pageData,g as default};
